import re
import urllib.parse
import urllib.request
import urllib.error
from datetime import datetime, timedelta
from html import unescape

API_URL = 'https://apis.data.go.kr/9710000/BillInfoService2/getBillInfoList'
PAGE_SIZE = 100

input_data = _items[0].get('json', {}) if _items else {}


def to_text(value, fallback=''):
    if value is None:
        return fallback
    text = str(value).strip()
    return text if text else fallback


def format_date(dt):
    return dt.strftime('%Y-%m-%d')


now = datetime.now()
start_date = to_text(input_data.get('start_date'), format_date(now))
end_date = to_text(input_data.get('end_date'), format_date(now))
age = to_text(input_data.get('age'), '22')

service_key = to_text(
    input_data.get('service_key')
    or input_data.get('apiKey')
    or input_data.get('API_KEY'),
    ''
)


def base_output():
    out = dict(input_data)
    out['start_date'] = start_date
    out['end_date'] = end_date
    out['age'] = age
    return out


if not service_key:
    out = base_output()
    out['error'] = 'Missing APIKEY_DATAGOKR'
    out['bills'] = []
    out['bill_count'] = 0
    return [{'json': out}]


def extract_tag_text(xml_text, tag_name):
    match = re.search(rf'<{tag_name}\b[^>]*>([\s\S]*?)</{tag_name}>', xml_text, flags=re.IGNORECASE)
    if not match:
        return ''
    return to_text(unescape(match.group(1)))


def parse_total_count(xml_text):
    patterns = [
        r'<totalCount>\s*([0-9]+)\s*</totalCount>',
        r'<list_total_count>\s*([0-9]+)\s*</list_total_count>',
    ]
    for pattern in patterns:
        match = re.search(pattern, xml_text, flags=re.IGNORECASE)
        if match:
            try:
                return int(match.group(1))
            except ValueError:
                pass
    return 0


def parse_bills_from_xml(xml_text):
    bills = []
    for match in re.finditer(r'<item\b[^>]*>([\s\S]*?)</item>', xml_text, flags=re.IGNORECASE):
        row = to_text(match.group(1))
        if not row:
            continue

        bill = {
            'proposeDate': extract_tag_text(row, 'proposeDt'),
            'billId': extract_tag_text(row, 'billId'),
            'billName': extract_tag_text(row, 'billName'),
            'billNumber': extract_tag_text(row, 'billNo'),
            'summary': extract_tag_text(row, 'summary'),
            'stage': extract_tag_text(row, 'procStageCd'),
            'proposerKind': extract_tag_text(row, 'proposerKind'),
            'assemblyNumber': age,
        }

        if not bill['summary']:
            continue
        bills.append(bill)

    return bills


def request_xml(url):
    request = urllib.request.Request(
        url,
        headers={
            'Accept': 'application/xml',
            'User-Agent': 'lawdigest-bills-pipeline/1.0',
        },
    )

    try:
        with urllib.request.urlopen(request, timeout=30) as response:
            try:
                status = response.status
            except Exception:
                status = response.getcode()

            try:
                reason = response.reason
            except Exception:
                reason = ''

            body = response.read().decode('utf-8', errors='ignore')
            return {'status': status, 'statusText': str(reason), 'body': body}
    except urllib.error.HTTPError as error:
        body = ''
        try:
            body = error.read().decode('utf-8', errors='ignore')
        except Exception:
            pass
        return {'status': error.code, 'statusText': str(error.reason), 'body': body}


def fetch_bills_page(page_no):
    params = {
        'serviceKey': service_key,
        'pageNo': str(page_no),
        'numOfRows': str(PAGE_SIZE),
        'start_ord': age,
        'end_ord': age,
        'start_propose_date': start_date,
        'end_propose_date': end_date,
    }
    query_string = urllib.parse.urlencode(params)
    response = request_xml(f'{API_URL}?{query_string}')

    if response['status'] < 200 or response['status'] >= 300:
        snippet = to_text(response.get('body', '')[:300])
        raise Exception(f"API HTTP {response['status']} {response.get('statusText', 'unknown')} - {snippet}")

    xml_text = response.get('body', '')
    return {
        'totalCount': parse_total_count(xml_text),
        'bills': parse_bills_from_xml(xml_text),
    }


try:
    bills = []
    page_no = 1

    first = fetch_bills_page(page_no)
    total_count = first['totalCount'] or len(first['bills'])
    bills.extend(first['bills'])

    while len(bills) < total_count:
        page_no += 1
        nxt = fetch_bills_page(page_no)
        if not nxt['bills']:
            break
        bills.extend(nxt['bills'])

    out = base_output()
    out['bills'] = bills
    out['bill_count'] = len(bills)
    return [{'json': out}]
except Exception as error:
    out = base_output()
    out['error'] = str(error)
    out['bills'] = []
    out['bill_count'] = 0
    return [{'json': out}]

