const bills = $json.bills || [];
const context = $json;
if (bills.length === 0) {
  return [{ json: { ...context, bills: [], bill_ids: [], dedup_query: "SELECT '_sentinel_' AS bill_id", new_bills: [], new_count: 0 } }];
}
const sqlEsc = v => `'${String(v).replace(/'/g, "''")}'`;
const idList = bills.map(b => sqlEsc(b.billId)).join(',');
const dedupQuery = [
  `SELECT bill_id FROM Bill WHERE bill_id IN (${idList}) AND brief_summary IS NOT NULL AND gpt_summary IS NOT NULL`,
  `SELECT bill_id FROM BillStaging WHERE bill_id IN (${idList}) AND status IN ('pending','processing')`,
  `SELECT '_sentinel_' AS bill_id`
].join('\nUNION ALL\n');
return [{ json: { ...context, bills, bill_ids: bills.map(b => b.billId), dedup_query: dedupQuery } }];

const existingItems = $input.all();
const existingIds = new Set(
  existingItems.map(i => i.json.bill_id).filter(id => id && id !== '_sentinel_')
);
const ctx = $items('Build Dedup Query', 0, 0)[0].json;
const allBills = ctx.bills || [];
const newBills = allBills.filter(b => b.billId && !existingIds.has(b.billId));
return [{ json: { ...ctx, new_bills: newBills, new_count: newBills.length } }];

const newBills = $json.new_bills || [];
const ctx = $json;
const sqlEsc = v => (v === null || v === undefined) ? 'NULL' : `'${String(v).replace(/\\/g, '').replace(/'/g, "''")}'`;
const values = newBills.map(b =>
  `(${sqlEsc(b.billId)}, ${parseInt(b.billNumber)||0}, ${sqlEsc(b.billName)}, ${sqlEsc(b.proposeDate)},
   ${sqlEsc(b.proposerKind||'CONGRESSMAN')}, ${sqlEsc(b.summary)}, ${sqlEsc(b.stage)}, ${sqlEsc(b.assemblyNumber||b.age||'22')})`
).join(',\n');
const query = `INSERT INTO BillStaging
  (bill_id, bill_number, bill_name, propose_date, proposer_kind, summary, stage, assembly_number)
VALUES ${values}
ON DUPLICATE KEY UPDATE
  bill_name   = VALUES(bill_name),
  summary     = VALUES(summary),
  stage       = VALUES(stage),
  status      = IF(status = 'failed', 'pending', status),
  updated_at  = NOW()`;
return [{ json: { ...ctx, stage_insert_query: query, staged_count: newBills.length } }];

const url = String($json.discord_webhook_url || '').trim();
if (!url || /^YOUR_/i.test(url)) return [];
const content = `📥 [bills-fetcher] ${$json.staged_count}건 신규 적재\n- run_id: ${$json.run_id}\n- 조회 기간: ${$json.start_date} ~ ${$json.end_date}\n- API 수신: ${$json.bill_count}건 / 신규: ${$json.staged_count}건`;
return [{ json: { ...$json, content } }];

const url = String($json.discord_webhook_url || '').trim();
if (!url || /^YOUR_/i.test(url)) return [];
const content = `ℹ️ [bills-fetcher] 신규 법안 없음 (${$json.bill_count}건 조회, 모두 기존 데이터)\n- 조회 기간: ${$json.start_date} ~ ${$json.end_date}`;
return [{ json: { ...$json, content } }];

const url = String($json.discord_webhook_url || '').trim();
if (!url || /^YOUR_/i.test(url)) return [];
const content = `⚠️ [bills-fetcher] API에서 데이터 없음\n- 조회 기간: ${$json.start_date} ~ ${$json.end_date}`;
return [{ json: { ...$json, content } }];

const cnt = Number($json.pending_count || 0);
const ctx = $items('Set Context', 0, 0)[0].json;
return [{ json: { ...ctx, pending_count: cnt } }];

const rows = $input.all().map(i => i.json);
const ctx = $items('Set Context', 0, 0)[0].json;
const sqlEsc = v => `'${String(v).replace(/'/g, "''")}'`;
const idList = rows.map(r => sqlEsc(r.bill_id)).join(',');
const markQuery = `UPDATE BillStaging SET status='processing', updated_at=NOW() WHERE bill_id IN (${idList})`;
return [{ json: { ...ctx, bills: rows, bill_count: rows.length, mark_processing_query: markQuery } }];

const ctx = $items('Aggregate Pending', 0, 0)[0].json;
const bills = ctx.bills || [];
return bills.map(b => ({
  json: {
    ...ctx,
    billId: b.bill_id,
    billName: b.bill_name,
    billNumber: b.bill_number,
    proposeDate: b.propose_date,
    proposerKind: b.proposer_kind,
    proposer_kind: b.proposer_kind,
    summary: b.summary,
    stage: b.stage,
    assemblyNumber: b.assembly_number,
    _staging_bill_id: b.bill_id,
  }
}));

const title = $json.billName || '';
const summary = String($json.summary || '').slice(0, 12000);
const unified_prompt = `아래 법안을 JSON 형식으로 분석해줘.

[법안명]
${title}

[본문]
${summary}

출력 형식:
{"briefSummary":"1문장 제목 (~하기 위한 ${title} 형태로 끝남)","gptSummary":"3~7개 항목 한국어 요약, 마지막 1문장 취지 정리"}`;
return [{ json: { ...$json, unified_prompt } }];

const src = $items('Build AI Prompts', 0, $itemIndex)[0].json;
let briefSummary = null, gptSummary = null;
try {
  const parts = $json.candidates?.[0]?.content?.parts ?? [];
  const raw = parts.map(p => p.text || '').join('').trim();
  if (raw) { const p = JSON.parse(raw); briefSummary = p.briefSummary || null; gptSummary = p.gptSummary || null; }
} catch(e) {}
return [{ json: { ...src, briefSummary, gptSummary, needs_fallback: !briefSummary || !gptSummary } }];

const src = $items('Parse Gemini Result', 0, $itemIndex)[0].json;
let { briefSummary, gptSummary } = src;
try {
  const content = $json.choices?.[0]?.message?.content;
  if (content) { const p = JSON.parse(content); briefSummary = p.briefSummary || briefSummary; gptSummary = p.gptSummary || gptSummary; }
} catch(e) {}
return [{ json: { ...src, briefSummary, gptSummary } }];

const toText = (v) => { if (v === undefined || v === null) return null; const t = String(v).trim(); return t.length ? t : null; };
const toInt = (v, d = 0) => { if (v === undefined || v === null || v === '') return d; const n = Number(String(v).replace(/,/g, '').trim()); return Number.isFinite(n) ? Math.trunc(n) : d; };
const sqlEscape = (v) => { if (v === undefined || v === null) return 'NULL'; const s = String(v).replace(/\\/g, '').replace(/'/g, "''"); return `'${s}'`; };
const billId = toText($json.billId);
if (!billId) return [];
const billUpsertQuery = `INSERT INTO Bill (bill_id, bill_number, bill_name, propose_date, proposer_kind, summary, gpt_summary, brief_summary, committee, stage, bill_result, bill_pdf_url, bill_link, modified_date) VALUES (${sqlEscape(billId)}, ${toInt($json.billNumber)}, ${sqlEscape($json.billName)}, ${sqlEscape($json.proposeDate)}, 'CONGRESSMAN', ${sqlEscape($json.summary)}, ${sqlEscape($json.gptSummary)}, ${sqlEscape($json.briefSummary)}, ${sqlEscape($json.committee)}, ${sqlEscape($json.stage)}, ${sqlEscape($json.billResult)}, ${sqlEscape($json.billPdfUrl)}, ${sqlEscape($json.bill_link)}, NOW()) ON DUPLICATE KEY UPDATE modified_date=NOW();`;
return [{ json: { ...$json, bill_upsert_query: billUpsertQuery } }];

const url = String($json.discord_webhook_url || '').trim();
if (!url || /^YOUR_/i.test(url)) return [];
const content = `✅ [bills-processor] 처리 완료\n- run_id: ${$json.run_id}`;
return [{ json: { ...$json, content } }];

const url = String($json.discord_webhook_url || '').trim();
if (!url || /^YOUR_/i.test(url)) return [];
const content = 'ℹ️ [bills-processor] 처리할 법안 없음 (BillStaging 비어있음)';
return [{ json: { ...$json, content } }];
